use std::collections::*;
use std::io;

fn trim_newline(s: &mut String) {
    if s.ends_with('\n') {
        s.pop();
        if s.ends_with('\r') {
            s.pop();
        }
    }
}
macro_rules! parse_input {
    ($t:ident) => {{
        let mut input_line = String::new();
        io::stdin().read_line(&mut input_line).unwrap();
        trim_newline(&mut input_line);
        input_line.parse::<$t>().unwrap()
    }};
}

macro_rules! split_input {
    ($t:ident) => {{
        parse_input!(String)
            .split(" ")
            .map(|z| z.parse::<$t>().unwrap())
            .collect::<Vec<$t>>()
    }};
}

struct xorrand {
    state: u64,
}
#[allow(dead_code)]
impl xorrand {
    fn rand(&mut self) -> u64 {
        let mut x = self.state;
        x ^= x << 13;
        x ^= x >> 7;
        x ^= x << 17;
        self.state = x;
        self.state.wrapping_mul(0x2545F4914F6CDD1Du64)
    }

    fn randint(&mut self, start: u64, end: u64) -> u64 {
        return (self.rand() % (end - start)) + start;
    }

    fn randfloat(&mut self) -> f64 {
        1.0 / (self.rand() as f64)
    }

    fn new(seed: u64) -> xorrand {
        xorrand { state: seed }
    }

    fn newtime() -> xorrand {
        let start = std::time::SystemTime::now();
        let ms = start
            .duration_since(std::time::UNIX_EPOCH)
            .unwrap()
            .as_secs();
        xorrand { state: ms }
    }

    fn shuffle<T: Clone>(&mut self, tgt: &mut Vec<T>) {
        for i in 0..tgt.len() - 1 {
            let j = self.randint(i as u64, tgt.len() as u64) as usize;
            let c = tgt[j].clone();
            tgt[j] = tgt[i].clone();
            tgt[i] = c;
        }
    }
}

